  id, source_trip_id, source_trip_version, published_by_user_id,
  cover_media_file_id, visibility, title, summary, snapshot_version,
  snapshot, moderation_status, published_at
)
SELECT
  seed_id::uuid,
  seed_trip_id::uuid,
  seed_snapshot_version::bigint,
  seed_user_id::uuid,
  seed_cover_media_id::uuid,
  seed_visibility,
  seed_title,
  seed_summary,
  seed_snapshot_version::bigint,
