  seed_published_at::timestamptz
FROM (VALUES
  -- Post 1
  ('10000000-0000-4000-8000-000000000001','c0000000-0000-4000-8000-000000000001','a0000000-0000-4000-8000-000000000002','b1000000-0000-4000-8000-000000000001','PUBLIC','제주도 3박4일 감성 여행 코스 정리','일출봉, 우도, 한라산까지. 스와이프로 모은 취향으로 짠 제주 코스입니다.',1,'{"days":4,"items":8}', 42, 8, 5, 3,'VISIBLE','2026-06-05 10:00:00+09'),
  -- Post 2
  ('10000000-0000-4000-8000-000000000002','c0000000-0000-4000-8000-000000000002','a0000000-0000-4000-8000-000000000003','b1000000-0000-4000-8000-000000000010','PUBLIC','부산 해운대 가족여행 후기','아이들과 함께한 부산 2박3일. 해운대부터 감천문화마을까지!',1,'{"days":3,"items":7}', 35, 5, 4, 1,'VISIBLE','2026-06-06 14:00:00+09'),
  -- Post 3
